        continue
    files=[p.relative_to(d).as_posix() for p in d.rglob('*') if p.is_file() and p.name!='SKILL.md']
    if files:
        kinds={f.split('/')[0] for f in files}
        rows.append((d.name,len(files),', '.join(sorted(kinds))))
print('skills_with_attachments', len(rows))
print('attachment_files_total', sum(r[1] for r in rows))
for name,n,kinds in rows:
    print(f'{name}\t{n}\t{kinds}')
