root=Path('/Users/bytedance/Documents/Obsidian Vault/awesome-codex-skills')
renamed=[]
conflicts=[]
for lang in ['en','zh']:
    for category in ['top-level','scientific-skills','mattpocock-skills']:
        base=root/lang/category
        if not base.exists():
            continue
        for d in sorted([p for p in base.rglob('*') if p.is_dir()]):
            src=d/(d.name + '.md')
            dst=d/'SKILL.md'
            if src.exists():
                if dst.exists():
                    conflicts.append((src, dst))
                else:
                    src.rename(dst)
                    renamed.append((src.relative_to(root), dst.relative_to(root)))
print('renamed_back', len(renamed))
if conflicts:
    print('conflicts', len(conflicts))
    for src,dst in conflicts[:20]:
        print(src, '->', dst)
