from pathlib import Path
root=Path('awesome-codex-skills')
for category in ['top-level','scientific-skills','mattpocock-skills']:
    en={p.relative_to(root/'en'/category).as_posix() for p in (root/'en'/category).rglob('*') if p.is_file()}
    zh={p.relative_to(root/'zh'/category).as_posix() for p in (root/'zh'/category).rglob('*') if p.is_file()}
    print(category, 'missing zh', len(en-zh), 'extra zh', len(zh-en))
print('en SKILL', sum(1 for _ in (root/'en').rglob('SKILL.md')))
print('zh SKILL', sum(1 for _ in (root/'zh').rglob('SKILL.md')))
